1	type Item = { type: string };
2	type Scenario = {
3	  steps: Array<{ op: string; items?: Item[] }>;
4	};
5	
6	const PROCESSING_FEE = 5;
7	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	};
14	
15	export function processScenario(scenario: unknown): unknown {
16	  const { steps } = scenario as Scenario;
17	  const results = steps.map((step) => {
18	    const items = step.items ?? [];
19	    const countsByType: Record<string, number> = {};
20	    for (const item of items) {
21	      countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
22	    }
23	    let policyBase = 0;
24	    for (const [type, count] of Object.entries(countsByType)) {
25	      if (type === "rune" && count === 3) {
26	        policyBase += 60;
27	      } else {
28	        policyBase += count * BASE_PREMIUM_BY_ITEM_TYPE[type];
29	      }
30	    }
31	    const firstInsurance = policyBase / 10;
32	    const premium = Math.ceil(policyBase + firstInsurance) + PROCESSING_FEE;
33	    return { premium };
34	  });
35	  return { results };
36	}
